var DATA=null,currentLetter='A';
var MUZARD_DATA=null; // index par nom de cinéaste

Promise.all([
  fetch('cineastes.json').then(function(r){return r.json()}),
  fetch('muzard.json').then(function(r){return r.json()}).catch(function(){return null;})
]).then(function(results){
  var data=results[0];
  var muzard=results[1];

  DATA=data;
  DATA.cineastes.forEach(function(c){
    if(c.tops_contributeurs){
      c.tops_contributeurs=c.tops_contributeurs.map(function(t){
        if(t==='MAT'||t==='MAT ')return 'MATHIEU MUZARD';
        if(t==='THOMAS F. FLAVIER')return 'THOMAS FLAVIER';
        if(t==='VINZ ORLOV')return 'VINZ J. ORLOV';
        if(t==='THOMAS D. DEMAEREL')return 'THOMAS DEMAEREL';
        if(t==='PEELSA')return 'PEELSA';
        if(t==='EDO VOLBEDA')return 'PEELSA';
        return t;
      });
    }
  });

  // Construire l'index Muzard : nom cinéaste → liste de films
  if(muzard && muzard.tops){
    MUZARD_DATA={};
    muzard.tops.forEach(function(top){
      MUZARD_DATA[top.cineaste]=top.films;
      // Alias pour duos : "NOM, Prenom & NOM2, Prenom2" -> cherche aussi dans cineastes.json
      var a=top.cineaste.split('&');
      if(a.length>1){
        var k=a.map(function(p){return p.trim().split(',')[0].trim()}).join(' & ');
        if(!MUZARD_DATA[k])MUZARD_DATA[k]=top.films;
      }
    });
  }

  init();
}).catch(function(){
  document.getElementById('cineaste-list').innerHTML='<div class="empty-msg">Erreur de chargement.</div>';
});

function enterSite(){
  document.getElementById('splash').classList.add('hidden');
  document.getElementById('main-wrapper').classList.add('visible');
}

function init(){buildAlpha();selectLetter('A')}

function toTitleCase(s){
  var r=s.charAt(0).toUpperCase()+s.slice(1).toLowerCase();
  var acc={'Thoracentese':'Thoracentèse','Frederic':'Frédéric','Clement':'Clément','Gregory':'Grégory'};
  return acc[r]||r;
}

function formatContribNamePlain(name){
  var p=name.trim().split(' ');
  if(p.length===1)return p[0];
  return p.slice(0,-1).map(toTitleCase).join(' ')+' '+p[p.length-1];
}
function formatContribName(name){
  var p=name.trim().split(' ');
  if(p.length===1)return '<span class="contrib-nom">'+p[0]+'</span>';
  var prenom=p.slice(0,-1).map(toTitleCase).join(' ');
  return '<span class="contrib-prenom">'+prenom+'</span> <span class="contrib-nom">'+p[p.length-1]+'</span>';
}

function formatNom(nom){
  if(nom.includes(',')){var i=nom.indexOf(',');return '<b>'+nom.slice(0,i)+'</b>'+nom.slice(i)}
  return '<b>'+nom+'</b>';
}
function formatDateSimple(n,d,v){
  if(!n)return '';if(d)return n+'\u2013'+d;if(v)return String(n);return String(n);
}
function formatDates(c){
  if(c.provisoire)return'(fiche provisoire)';
  if(c.duo&&Array.isArray(c.naissance)){
    var d1=formatDateSimple(c.naissance[0],c.deces[0],c.vivant[0]);
    var d2=formatDateSimple(c.naissance[1],c.deces[1],c.vivant[1]);
    if(d1||d2)return(d1||'?')+'\u2002/\u2002'+(d2||'?');return '';
  }
  return formatDateSimple(c.naissance,c.deces,c.vivant);
}

function navigateProfil(name){
  navigate('profil');
  renderProfil(name);
}

var _profilCineasteAll=false,_profilFilmsAll=false,_currentContribData=null;

function parseFilmStr(s){
  // Cas standard : TITRE (REALISATEUR, ANNEE)
  var m=s.match(/^(.*?)\s*\(([^,()]+),\s*(\d{4})\)\s*$/);
  if(m)return{titre:m[1].trim(),realisateur:m[2].trim(),annee:m[3]};

  // Cas plage d'années : TITRE (REAL, AAAA-AA) ou (REAL, AAAA-AAAA)
  var m2=s.match(/^(.*?)\s*\(([^,()]+),\s*(\d{4})[\-–](\d{2,4})\)\s*$/);
  if(m2){
    var debut=m2[3];var fin=m2[4];
    if(fin.length===2)fin=debut.slice(0,2)+fin;
    return{titre:m2[1].trim(),realisateur:m2[2].trim(),annee:debut+'-'+fin};
  }

  // Cas sans virgule avant année : TITRE (REAL AAAA-AA)
  var m3=s.match(/^(.*?)\s*\(([^()]+?)\s+(\d{4})[\-–](\d{2,4})\)\s*$/);
  if(m3){
    var debut=m3[3];var fin=m3[4];
    if(fin.length===2)fin=debut.slice(0,2)+fin;
    return{titre:m3[1].trim(),realisateur:m3[2].trim(),annee:debut+'-'+fin};
  }

  // Cas sans année : TITRE (REALISATEUR) — ex: FANNY ET ALEXANDRE (BERGMAN)
  // Chercher des noms connus pour deviner l'année
  var ANNEES_CONNUES={
    'BERGMAN':'1982',  // Fanny et Alexandre
  };
  var m4=s.match(/^(.*?)\s*\(([^,()\d]+)\)\s*$/);
  if(m4){
    var real=m4[2].trim();
    var anneeGuess=null;
    for(var k in ANNEES_CONNUES){if(real.indexOf(k)!==-1){anneeGuess=ANNEES_CONNUES[k];break;}}
    return{titre:m4[1].trim(),realisateur:real,annee:anneeGuess||''};
  }

  // Cas avec parenthèses dans le titre : HISTOIRE(S) DU CINEMA (GODARD, 1988-98)
  var m5=s.match(/^(.*\))\s*\(([^,()]+),\s*(\d{4})[\-–](\d{2,4})\)\s*$/);
  if(m5){
    var debut=m5[3];var fin=m5[4];
    if(fin.length===2)fin=debut.slice(0,2)+fin;
    return{titre:m5[1].trim(),realisateur:m5[2].trim(),annee:debut+'-'+fin};
  }
  var m6=s.match(/^(.*\))\s*\(([^,()]+),\s*(\d{4})\)\s*$/);
  if(m6)return{titre:m6[1].trim(),realisateur:m6[2].trim(),annee:m6[3]};

  return{titre:s,realisateur:'',annee:''};
}

function buildPortraitSrc(f){
  var particles=['De','Van','von','Von','Du','du','Di','di','Da','da','Le','La','del','Del','Della','lo','Lo'];
  if(f==='Straub/Huillet')return{src:'portraits/portrait-Straub.jpg',initials:'S'};
  var parts=f.split(' ');
  var last=parts[parts.length-1];
  var secondLast=parts.length>1?parts[parts.length-2]:'';
  var lastName=particles.indexOf(secondLast)!==-1?secondLast+' '+last:last;
  return{src:'portraits/portrait-'+lastName+'.jpg',initials:lastName.charAt(0)};
}

function renderProfilFavs(favs){
  var grid=document.getElementById('profil-favs-grid');grid.innerHTML='';
  if(!favs.length){grid.innerHTML='<div class="empty-msg">Aucun cinéaste favori renseigné</div>';return}
  favs.forEach(function(f,fi){
    var p=buildPortraitSrc(f);
    var isFirst=fi===0;
    var item=document.createElement('div');item.className='profil-fav-item';
    var imgClass='profil-fav-portrait'+(isFirst?' profil-fav-first':'');
    var initClass='profil-fav-initials'+(isFirst?' profil-fav-first':'');
    item.innerHTML='<img class="'+imgClass+'" src="'+p.src+'" alt="'+f+'" onerror="this.style.display=\'none\';this.nextElementSibling.style.display=\'flex\'">'
      +'<div class="'+initClass+'" style="display:none">'+p.initials+'</div>'
      +'<div class="profil-fav-name">'+f+'</div>';
    grid.appendChild(item);
  });
}

function normalizeAutreNom(n){
  // Duos → format court
  if(n.indexOf('STRAUB')!==-1&&n.indexOf('HUILLET')!==-1)return 'STRAUB/HUILLET';
  if(n.indexOf('REIS')!==-1&&n.indexOf('CORDEIRO')!==-1)return 'REIS/CORDEIRO';
  if(n.indexOf('POWELL')!==-1&&n.indexOf('PRESSBURGER')!==-1)return 'POWELL/PRESSBURGER';
  return n;
}
function renderAutresCineaste(list,showAll){
  var el=document.getElementById('profil-autres-cineaste');
  var btn=document.getElementById('profil-autres-cineaste-btn');
  var shown=showAll?list:list.slice(0,10);
  el.innerHTML=shown.map(function(n,i){
    var display=normalizeAutreNom(n);
    var cls='profil-autre-item'+(display==='Apichatpong WEERASETHAKUL'?' profil-autre-small':'');
    return '<div class="'+cls+'"><span class="profil-autre-num">'+(i+1)+'.</span> '+display+'</div>';
  }).join('');
  if(list.length<=10){btn.style.display='none';}
  else{btn.style.display='inline-flex';btn.textContent=showAll?'Voir moins ↑':'Voir les '+(list.length-10)+' autres ↓';}
}

function renderFilmsBlock(elId,list,showAll,limit,btnId){
  var el=document.getElementById(elId);
  var btn=document.getElementById(btnId);
  var shown=showAll?list:list.slice(0,limit);
  el.innerHTML=shown.map(function(s){
    var f=parseFilmStr(s);
    var info=f.realisateur+(f.annee?', '+f.annee:'');
    return'<div class="profil-film-item"><div class="profil-film-titre">'+f.titre+'</div>'+(info?'<div class="profil-film-info">'+info+'</div>':'')+'</div>';
  }).join('');
  if(list.length<=limit){btn.style.display='none';}
  else{btn.style.display='inline-flex';btn.textContent=showAll?'Voir moins ↑':'Voir les '+(list.length-limit)+' autres ↓';}
}

function toggleVoirPlus(type){
  if(type==='cineaste'){
    _profilCineasteAll=!_profilCineasteAll;
    renderAutresCineaste(_currentContribData.cineaste_autres,_profilCineasteAll);
  } else {
    _profilFilmsAll=!_profilFilmsAll;
    renderFilmsBlock('profil-films-autres',_currentContribData.film_autres,_profilFilmsAll,6,'profil-films-autres-btn');
  }
}

function renderProfil(name){
  var cin=DATA.cineastes.filter(function(c){return c.tops_contributeurs&&c.tops_contributeurs.indexOf(name)!==-1});
  document.getElementById('profil-name').innerHTML=formatContribName(name);
  var avatarEl=document.getElementById('profil-avatar');
  if(avatarEl){
    avatarEl.textContent=getInitiales(name);
    var avatarUrl=AVATAR_URLS[name];
    if(avatarUrl){
      var img=new Image();
      img.onload=function(){
        var el=document.getElementById('profil-avatar');
        if(el){var imgEl=document.createElement('img');imgEl.src=avatarUrl;imgEl.alt=name;el.innerHTML='';el.appendChild(imgEl);}
      };
      img.src=avatarUrl;
    }
  }
  var totalFilms=0;
  if(MUZARD_DATA&&name==='MATHIEU MUZARD'){
    cin.forEach(function(x){var films=MUZARD_DATA[x.nom];if(films)totalFilms+=films.length;});
  }
  var statTxt=cin.length+' top'+(cin.length>1?'s':'')+' posté'+(cin.length>1?'s':'');
  if(totalFilms>0)statTxt+=' · '+totalFilms+' film'+(totalFilms>1?'s':'');
  document.getElementById('profil-stat').textContent=statTxt;
  _profilCineasteAll=false;_profilFilmsAll=false;

  var contrib=null;
  for(var i=0;i<CONTRIB_DATA.length;i++){if(CONTRIB_DATA[i].json_name===name){contrib=CONTRIB_DATA[i];break}}
  _currentContribData=contrib||{cineaste_coeur:[],cineaste_autres:[],film_coeur:[],film_autres:[],presentation:null};

  renderProfilFavs(FAVORIS[name]||[]);

  var autresBlock=document.getElementById('profil-autres-cineaste-block');
  if(_currentContribData.cineaste_autres&&_currentContribData.cineaste_autres.length){
    autresBlock.style.display='';
    var titreAutres=autresBlock.querySelector('.profil-section-title');
    if(titreAutres){titreAutres.textContent='Autres cinéastes appréciés';}
    renderAutresCineaste(_currentContribData.cineaste_autres,false);
  } else {autresBlock.style.display='none';}

  var filmsCoeurBlock=document.getElementById('profil-films-coeur-block');
  if(_currentContribData.film_coeur&&_currentContribData.film_coeur.length){
    filmsCoeurBlock.style.display='';
    var elFC=document.getElementById('profil-films-coeur');
    elFC.innerHTML=_currentContribData.film_coeur.map(function(s){
      var f=parseFilmStr(s);var info=f.realisateur+(f.annee?', '+f.annee:'');
      return'<div class="profil-film-item"><div class="profil-film-titre">'+f.titre+'</div>'+(info?'<div class="profil-film-info">'+info+'</div>':'')+'</div>';
    }).join('');
  } else {filmsCoeurBlock.style.display='none';}

  var filmsAutresBlock=document.getElementById('profil-films-autres-block');
  if(_currentContribData.film_autres&&_currentContribData.film_autres.length){
    filmsAutresBlock.style.display='';
    renderFilmsBlock('profil-films-autres',_currentContribData.film_autres,false,6,'profil-films-autres-btn');
  } else {filmsAutresBlock.style.display='none';}

  var presBlock=document.getElementById('profil-presentation-block');
  if(_currentContribData.presentation){
    presBlock.style.display='';
    document.getElementById('profil-presentation-text').textContent=_currentContribData.presentation;
  } else {presBlock.style.display='none';}

}


function navigate(page){
  if(page==='profil'&&!_currentContribData){page='contributeurs';}
  document.querySelectorAll('.page').forEach(function(p){p.classList.remove('visible')});
  var el=document.getElementById('page-'+page);
  void el.offsetWidth;
  el.classList.add('visible');
  document.querySelectorAll('.nav a').forEach(function(a){a.classList.remove('active')});
  var navEl=document.getElementById('nav-'+page);
  if(navEl)navEl.classList.add('active');
  if(page==='contributeurs')renderContributeurs();
  if(page==='statistiques')renderStatistiques();
  // Afficher le bouton retour uniquement sur le profil
  var bottomNav=document.getElementById('bottom-nav');
  if(bottomNav)bottomNav.style.display=(page==='profil'?'flex':'none');
  window.scrollTo(0,0);
}

function getLetterData(l){return DATA?DATA.cineastes.filter(function(c){return c.nom.charAt(0).toUpperCase()===l}):[]}

function buildAlpha(){
  var bar=document.getElementById('alpha-bar');bar.innerHTML='';
  'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('').forEach(function(l){
    var items=getLetterData(l);
    if(!items.length)return;
    var col=document.createElement('div');
    col.className='alpha-col has-data'+(l===currentLetter?' active':'');
    col.innerHTML='<div class="alpha-char">'+l+'</div>';
    col.onclick=function(){selectLetter(l)};
    bar.appendChild(col);
  });
}

function selectLetter(l){
  currentLetter=l;document.getElementById('search-input').value='';
  document.querySelectorAll('.alpha-col').forEach(function(col){
    var char=col.querySelector('.alpha-char');
    col.classList.toggle('active',char&&char.textContent===l);
  });
  var items=getLetterData(l);items.sort(function(a,b){return a.nom.localeCompare(b.nom,'fr')});
  renderList(items);
}

function renderList(items){
  var list=document.getElementById('cineaste-list'),count=document.getElementById('list-count');
  list.innerHTML='';
  if(!items.length){list.innerHTML='<div class="empty-msg">Aucun résultat</div>';count.textContent='';return}
  count.textContent=items.length+' cinéaste'+(items.length>1?'s':'');
  var maxTops=1;items.forEach(function(c){var n=(c.tops_contributeurs||[]).length;if(n>maxTops)maxTops=n});
  items.forEach(function(c){
    var row=document.createElement('div');row.className='cineaste-row';
    var nb=(c.tops_contributeurs||[]).length;
    var dates=formatDates(c);
    var datesHtml=dates?'<span class="c-dates">'+dates+'</span>':'';
    row.innerHTML='<div class="c-bar"></div>'
      +'<div class="c-info"><span class="c-name">'+formatNom(c.nom)+'</span>'+datesHtml+'</div>'
      +'<div class="c-badge">'+nb+'</div>';
    row.onclick=function(){openFiche(c)};list.appendChild(row);
  });
}

function normStr(s){
  return s.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'');
}
function filterList(){
  var q=normStr(document.getElementById('search-input').value.trim());
  if(!q){selectLetter(currentLetter);return}
  var r=DATA.cineastes.filter(function(c){
    return normStr(c.nom).indexOf(q)!==-1;
  });
  r.sort(function(a,b){return a.nom.localeCompare(b.nom,'fr')});
  document.querySelectorAll('.alpha-col').forEach(function(col){col.classList.remove('active')});
  renderList(r);
}

function openFiche(c){
  var nb=(c.tops_contributeurs||[]).length;
  var squareW=Math.max(20,Math.min(80,Math.round(20+(nb/24)*60)))+'px';
  var fbHtml=c.url_facebook?'<a class="fiche-fb-link" href="'+c.url_facebook+'" target="_blank">Voir la fiche sur Facebook &#8599;</a>':'';
  var blocksDiv=document.createElement('div');
  blocksDiv.className='contrib-blocks';blocksDiv.id='contrib-blocks';
  if(nb>0){
    c.tops_contributeurs.forEach(function(t){
      var films=MUZARD_DATA&&t==='MATHIEU MUZARD'?MUZARD_DATA[c.nom]:null;
      var hasFilms=films&&films.length>0;
      var blockId='cb-'+t.replace(/[^a-zA-Z0-9]/g,'');
      var block=document.createElement('div');
      block.className='fiche-contrib-block'+(hasFilms?' has-films':'');
      block.id=blockId;block.setAttribute('data-contrib',t);
      var header=document.createElement('div');header.className='fiche-contrib-header';
      var nameEl=document.createElement('div');nameEl.className='fiche-contrib-name';
      nameEl.innerHTML=formatContribNamePlain(t)+(hasFilms?' <span class="fiche-contrib-count">('+films.length+')</span>':'');
      header.appendChild(nameEl);
      if(hasFilms){var tog=document.createElement('span');tog.className='fiche-contrib-toggle';tog.innerHTML='&#9660;';header.appendChild(tog);}
      block.appendChild(header);
      if(hasFilms){
        var ol=document.createElement('ol');ol.className='fiche-contrib-films';
        films.forEach(function(f){
          var li=document.createElement('li');
          var s1=document.createElement('span');s1.className='fiche-muzard-film';s1.textContent=f.titre;
          var s2=document.createElement('span');s2.className='fiche-muzard-annee';s2.textContent=f.annee;
          li.appendChild(s1);li.appendChild(s2);ol.appendChild(li);
        });
        block.appendChild(ol);
      }
      blocksDiv.appendChild(block);
    });
  } else {
    blocksDiv.innerHTML='<div class="empty-msg">Aucun top posté pour ce cinéaste</div>';
  }
  var fiche=document.getElementById('fiche-content');
  fiche.innerHTML='<div class="fiche-back" onclick="closeFiche()">← Retour</div>'
    +'<div class="fiche-header" style="--sq:'+squareW+'"><div class="fiche-name">'+formatNom(c.nom)+'</div><div class="fiche-dates">'+formatDates(c)+'</div></div>'
    +'<div class="fiche-body"><div class="fiche-stat-block"><div class="fiche-stat-number">'+nb+'</div><div class="fiche-stat-bar"></div><div class="fiche-stat-label">tops postés</div></div>'
    +'<div class="fiche-contribs"><div class="fiche-section">Tops postés par</div></div></div>'+fbHtml;
  fiche.querySelector('.fiche-contribs').appendChild(blocksDiv);
  blocksDiv.addEventListener('click',function(e){
    e.stopPropagation();
    var header=e.target.closest('.fiche-contrib-header');if(!header)return;
    var block=header.closest('.fiche-contrib-block');if(!block)return;
    if(block.classList.contains('has-films')){block.classList.toggle('open');}
    else{var name=block.getAttribute('data-contrib');if(name)openContribDetail(name);}
  });
  document.getElementById('fiche-overlay').classList.add('visible');
  document.body.style.overflow='hidden';
}

function toggleAccordeon(id){
  var block=document.getElementById(id);
  if(!block)return;
  block.classList.toggle('open');
}

function closeFiche(){document.getElementById('fiche-overlay').classList.remove('visible');document.body.style.overflow='';}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeFiche()});

var _contribs=[];

function renderContributeurs(){
  if(!DATA)return;
  var list=document.getElementById('contrib-list');
  _contribs=DATA.contributeurs
    .filter(function(c){var n=(c.prenom+(c.nom?' '+c.nom:'')).trim();return n!=='version 22.8'&&n!==''})
    .map(function(c){
      var dn=(c.prenom+(c.nom?' '+c.nom:'')).trim();var nb=0;
      DATA.cineastes.forEach(function(x){if(x.tops_contributeurs&&x.tops_contributeurs.indexOf(dn)!==-1)nb++});
      return{name:dn,tops:nb};
    });
  _contribs.sort(function(a,b){return b.tops-a.tops});
  var maxTops=_contribs.length>0?_contribs[0].tops:1;
  list.innerHTML='';
  _contribs.forEach(function(contrib){
    var ratio=contrib.tops/maxTops;
    var tier=ratio>0.75?4:ratio>0.5?3:ratio>0.25?2:1;
    var div=document.createElement('div');
    div.className='contrib-bubble';
    div.setAttribute('data-tops-tier',tier);
    div.setAttribute('data-name',contrib.name);
    div.innerHTML='<div class="contrib-bubble-band"></div>'
      +'<div class="contrib-bubble-body">'
      +'<div class="contrib-card-name">'+formatContribName(contrib.name)+'</div>'
      +'<div class="contrib-card-stat">'
      +'<span class="contrib-card-stat-num">'+contrib.tops+'</span>'
      +'<span class="contrib-card-stat-label"> top'+(contrib.tops>1?'s':'')+' postés</span>'
      +'</div></div>';
    div.onclick=function(){navigateProfil(this.getAttribute('data-name'));};
    list.appendChild(div);
  });
}

function openContribDetail(name){
  var cin=DATA.cineastes.filter(function(c){return c.tops_contributeurs&&c.tops_contributeurs.indexOf(name)!==-1});
  cin.sort(function(a,b){return a.nom.localeCompare(b.nom,'fr')});
  var favs=FAVORIS[name]||[];
  var favsHtml=favs.length
    ?'<div class="fiche-section" style="margin:1.2rem 1.8rem 0.5rem">Cinéastes favoris</div>'
     +'<div class="contrib-grid" style="padding:0 1.8rem">'+favs.map(function(f){return '<span class="contrib-tag" style="cursor:default">&#10084; '+f+'</span>'}).join('')+'</div>'
    :'';
  var listHtml='<div class="cineaste-list" style="margin-top:1rem">';
  cin.forEach(function(c){
    var dates=formatDates(c);var dh=dates?'<span class="c-dates">'+dates+'</span>':'';
    listHtml+='<div class="cineaste-row" onclick="closeFiche();var c=DATA.cineastes.find(function(x){return x.fbid===\''+c.fbid+'\'});if(c)openFiche(c)">'
      +'<div class="c-bar"></div>'
      +'<div class="c-info"><span class="c-name">'+formatNom(c.nom)+'</span>'+dh+'</div></div>';
  });listHtml+='</div>';

  var sqW=Math.max(20,Math.min(80,Math.round(20+(cin.length/24)*60)))+'px';
  document.getElementById('fiche-content').innerHTML=
    '<div class="fiche-back" onclick="closeFiche()">\u2190 Retour</div>'
    +'<div class="fiche-header" style="--sq:'+sqW+'">' 
      +'<div class="fiche-name" style="font-size:30px">'+formatContribNamePlain(name)+'</div>'
      +'<div class="fiche-dates">'+cin.length+' top'+(cin.length>1?'s':'')+' postés</div>'
    +'</div>'
    +favsHtml
    +'<div class="fiche-section" style="margin:1.2rem 1.8rem 0.5rem">Cinéastes classés</div>'
    +listHtml;

  document.getElementById('fiche-overlay').classList.add('visible');
  document.body.style.overflow='hidden';
}

function renderStatistiques(){
  if(!DATA)return;
  var totalC=DATA.cineastes.length;
  var totalContribs=DATA.contributeurs.filter(function(c){var n=(c.prenom+(c.nom?' '+c.nom:'')).trim();return n!=='version 22.8'&&n!==''}).length;
  var enA=0,dec=0,st=0,tt=0;
  DATA.cineastes.forEach(function(c){var nb=(c.tops_contributeurs||[]).length;tt+=nb;if(c.vivant===true)enA++;if(c.vivant===false)dec++;if(nb===0)st++});

  document.getElementById('stats-hero').innerHTML=
    mkHero(totalC,'Cinéastes')
    +mkHero(tt,'Tops postés')
    +mkHero(totalContribs,'Contributeurs');
  document.getElementById('stats-secondary').innerHTML='';

  var ranked=DATA.cineastes.slice()
    .sort(function(a,b){return(b.tops_contributeurs||[]).length-(a.tops_contributeurs||[]).length})
    .filter(function(c){return(c.tops_contributeurs||[]).length>15});

  document.getElementById('ranking-cineastes').innerHTML=ranked.map(function(c,i){
    var nb=(c.tops_contributeurs||[]).length;
    var rankClass=i<3?'ranking-rank top3':'ranking-rank';
    return '<div class="ranking-row" onclick="navigate(\'index\');setTimeout(function(){var x=DATA.cineastes.find(function(y){return y.fbid===\''+c.fbid+'\'});if(x)openFiche(x)},100)">'
      +'<div class="'+rankClass+'">'+(i+1)+'</div>'
      +'<div class="ranking-name">'+formatNom(c.nom)+'</div>'
      +'<div class="ranking-value">'+nb+'&thinsp;tops</div></div>';
  }).join('');
}

function mkHero(v,l,sub){
  return '<div class="stat-hero-item"><span class="stat-hero-value">'+v+'</span><span class="stat-hero-label">'+l+'</span>'+(sub?'<span class="stat-hero-sublabel">'+sub+'</span>':'')+'</div>';
}
